        // Slight nebula haze so the starfield breathes without becoming a pasted background.
        float haze = pow(max(0.0, 1.0 - abs(dir.y)), 2.4);
        vec3 hazeCol = mix(vec3(0.01, 0.018, 0.035), vec3(0.03, 0.025, 0.06), 0.5 + 0.5 * sin(iTime * 0.15 + dir.x * 3.0));
