      vec3 accretionDiskColor(vec3 hit, vec3 dir) {
        float radius = length(hit.xz);
        float radial = smoothstep(uDiskInner, uDiskInner + 1.15, radius) * (1.0 - smoothstep(uDiskOuter - 1.8, uDiskOuter, radius));
        float normalizedR = clamp((radius - uDiskInner) / max(uDiskOuter - uDiskInner, 0.001), 0.0, 1.0);

        float angle = atan(hit.z, hit.x);
        float swirl = sin(angle * 10.0 - iTime * (2.8 + normalizedR * 4.5) + radius * 1.5);
        float filaments = 0.62 + 0.38 * sin(angle * 24.0 + radius * 5.5 - iTime * 7.0);
        float turbulence = 0.72 + 0.28 * sin(radius * 8.0 - iTime * 5.0 + swirl * 1.2);

        vec3 tangent = normalize(vec3(-hit.z, 0.0, hit.x));
        float los = dot(tangent, -dir);
