        vec3 innerHot = vec3(1.8, 1.2, 0.55);
        vec3 midWarm = vec3(1.45, 0.62, 0.22);
        vec3 outerCool = vec3(0.88, 0.24, 0.09);
        vec3 base = mix(innerHot, midWarm, normalizedR);
        base = mix(base, outerCool, pow(normalizedR, 1.35));

