      vec3 photonRingGlow(vec3 pos, vec3 dir) {
        float r = length(pos);
        float equatorial = exp(-abs(pos.y) * 2.5);
        float ring = exp(-pow(abs(r - (uBhRadius * 2.6)), 2.0) * 5.2);
        float facing = 0.55 + 0.45 * pow(max(dot(normalize(-pos), dir), 0.0), 2.0);
        vec3 warm = vec3(1.25, 0.82, 0.38);
        vec3 cool = vec3(0.62, 0.78, 1.18);
        return mix(cool, warm, ring) * ring * equatorial * facing * 0.18;
      }

      void main() {
        vec2 uv = vUv * 2.0 - 1.0;
        float aspect = max(iResolution.x, 1.0) / max(iResolution.y, 1.0);
        uv.x *= aspect;

        vec3 camDir = normalize(iCameraDir);
        vec3 camRight = normalize(cross(camDir, iCameraUp));
        vec3 camUp = cross(camRight, camDir);
        float fovRad = iFov * PI / 180.0;
        float focalLength = 1.0 / max(tan(fovRad * 0.5), 1e-4);
        vec3 rayDir = normalize(camRight * uv.x + camUp * uv.y + camDir * focalLength);
        vec3 rayOrigin = iCameraPos;

        vec3 pos = rayOrigin;
        vec3 dir = rayDir;
        vec3 colorAccum = vec3(0.0);
        vec3 glowAccum = vec3(0.0);
        bool escaped = false;

        for (int i = 0; i < MAX_STEPS; i++) {
          float r = length(pos);
          if (r < uBhRadius) {
            // Absorbed: keep glow visible rather than returning black.
            glowAccum += vec3(0.35, 0.22, 0.12) * 0.12;
            break;
          }
          if (r > FAR_CLIP) {
            escaped = true;
            break;
          }

          float diskZone = smoothstep(uDiskOuter + 8.0, uDiskInner + 1.0, r);
          float stepLen = mix(0.85, 0.12, diskZone);
          stepLen = min(stepLen, max(0.06, r * 0.06));

          // Explicit ray-plane intersection against the y=0 accretion disk to avoid skipping it at larger steps.
          if (abs(dir.y) > 1e-5) {
            float tPlane = -pos.y / dir.y;
            if (tPlane > 0.0 && tPlane <= stepLen * 1.02) {
              vec3 hit = pos + dir * tPlane;
              float rad = length(hit.xz);
              if (rad >= uDiskInner && rad <= uDiskOuter) {
                vec3 diskCol = accretionDiskColor(hit, dir);
                float lensBoost = 1.0 + 0.6 * exp(-pow(rad - uDiskInner, 2.0) * 0.4);
                colorAccum += diskCol * lensBoost * 0.25;
                glowAccum += diskCol * 0.06;
              }
            }
          }

          // Approximate geodesic bending toward the center.
          vec3 gravDir = -normalize(pos);
          float bend = uLensStrength / max(r * r, 0.06);
          dir = normalize(dir + gravDir * bend * stepLen);

          glowAccum += photonRingGlow(pos, dir);
          glowAccum += vec3(1.0, 0.7, 0.35) * (0.006 / (pow(max(r - uBhRadius, 0.001), 1.45) + 0.18));

          pos += dir * stepLen;
        }

        vec3 finalColor = colorAccum + glowAccum;
        if (escaped) {
          vec3 stars = starfield(dir);
          // Lensing vignette around the black hole silhouette.
          float horizonDir = length(cross(normalize(-rayOrigin), rayDir));
          float lensRing = exp(-pow((horizonDir - 0.14) * 7.0, 2.0));
          finalColor += stars;
          finalColor += vec3(1.0, 0.72, 0.38) * lensRing * 0.42;
        } else {
          finalColor += vec3(0.012, 0.014, 0.02);
        }

        // Central shadow with slight ambient lift so it reads as silhouette rather than flat black frame.
        float centerGlow = exp(-pow(length(uv) * 1.75, 2.4));
        finalColor += vec3(0.01, 0.012, 0.02) * centerGlow * 0.4;

        finalColor = vec3(1.0) - exp(-finalColor * uExposure);
        finalColor = pow(finalColor, vec3(0.92));

        gl_FragColor = vec4(finalColor, 1.0);
      }
