      renderer.getDrawingBufferSize(sizeVec);
      uniforms.iResolution.value.set(Math.max(sizeVec.x, 1), Math.max(sizeVec.y, 1));
      uniforms.iCameraPos.value.copy(camera.position);
      camera.getWorldDirection(dirVec);
      uniforms.iCameraDir.value.copy(dirVec);
      uniforms.iCameraUp.value.copy(camera.up);
      uniforms.iFov.value = camera.fov;

